p.m:
\displaystyle{\begin{aligned}
   {\frac{\frac{2}{r}+\frac{6}{y}}{\frac{2}{r}-\frac{2}{y}}} 
      \amp = {\frac{\frac{2}{r}+\frac{6}{y}}{\frac{2}{r}-\frac{2}{y}}} \cdot \frac{{ry}}{{ry}} \\
      \amp = {\frac{\left(\frac{2}{r}+\frac{6}{y}\right)ry}{\left(\frac{2}{r}-\frac{2}{y}\right)ry}} \\
      \amp = \frac{\frac{2}{r} \cdot r y +\frac{6}{y} \cdot r y }{\frac{2}{r} \cdot r y  - \frac{2}{y} \cdot r y } \\
      \amp = \frac{2 y + 6 r}{2 y - 2 r} \\
      \amp = {\frac{2\mathopen{}\left(y+3r\right)}{2\mathopen{}\left(y-r\right)}} \\
      \amp = {\frac{y+3r}{y-r}}
\end{aligned}
    }
